import React, { useState, useEffect } from 'react';

import { getStats } from '../services/api';

function LiveStats() {

  const [stats, setStats] = useState({});

  useEffect(() => {

    const fetchStats = async () => {

      try {
        const response = await getStats();
        console.log("Stats Response:", response.data);
        setStats(response.data);
      } catch (error) {
        console.error('Error fetching stats:', error);
      }
    };

    fetchStats();

    const interval = setInterval(fetchStats, 5000);

    return () => clearInterval(interval);

  }, []);

  return (
    <div className="stats-card" style={{ gridColumn: '1 / -1', display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '20px' }}>
      <h2 style={{ gridColumn: '1 / -1', marginTop: 0, marginBottom: '20px', color: '#fff' }}>Real-Time System Stats</h2>

      <div className="stat-item">
        <span className="stat-label">CO₂ Emissions</span>
        <span className="stat-value neon-green">{stats.co2 || '0.0000 kg'}</span>
      </div>

      <div className="stat-item">
        <span className="stat-label">Power Usage</span>
        <span className="stat-value neon-blue">{stats.energy || '0 W'}</span>
      </div>

      <div className="stat-item">
        <span className="stat-label">CPU Usage</span>
        <span className="stat-value" style={{ color: '#ff0055', textShadow: '0 0 20px rgba(255, 0, 85, 0.3)' }}>{stats.cpu || '0'} %</span>
      </div>

      <div className="stat-item">
        <span className="stat-label">Memory Usage</span>
        <span className="stat-value" style={{ color: '#ffee00', textShadow: '0 0 20px rgba(255, 238, 0, 0.3)' }}>{stats.memory || '0 / 0 GB'}</span>
      </div>
    </div>
  );
}

export default LiveStats;
